// Migration: điền "Saturday" vào các note đang trống
(function migrateNoteDates(){
  const datePattern=/^\d{1,2}\/\d{1,2}\/\d{4}$/;
  let changed=false;
  sessions.forEach(s=>{
    if(!s.note||s.note.trim()===''||datePattern.test(s.note.trim())){
      s.note='Saturday';
      changed=true;
    }
  });
  if(changed)ss('hl_sessions',sessions);
})();

